    if assertion_el is None:
        abort(400, "No Assertion present in SAMLResponse")
    if assertion_el.tag.endswith("EncryptedAssertion"):
        abort(400, "EncryptedAssertion not supported in this example SP")

    _validate_signature_presence(response_root, assertion_el)

