    if not _validate_audience(audiences):
        abort(400, "SAML Audience restriction failed")

    nameid = _extract_nameid(assertion_el)
    attrs = _extract_attributes(assertion_el)

    if not nameid and not attrs:
        abort(400, "No user identity found in SAML Assertion")

    user = {
        "nameid": nameid,
        "attributes": attrs,
        "issuer": issuer,
        "audiences": audiences,
        "not_before": not_before,
        "not_on_or_after": not_on_or_after,
        "authenticated_at": _now_epoch(),
    }

